def test_input_characterization_reports_all_tile_inventory(encoding_primitives):
    source_scope = encoding_primitives["source_scope"]
    characterization = encoding_primitives["input_geometry_characterization"]
    assert source_scope["tile_count"] > 1
    assert source_scope["feature_count"] > 0
    assert characterization["geometry_type_feature_counts"]
    assert sum(characterization["geometry_type_feature_counts"].values()) == (
        source_scope["feature_count"]
    )
    assert characterization["measured_geometry_sample_counts"]["polylines"] > 0
    assert characterization["measured_geometry_sample_counts"]["polygon_exterior_rings"] > 0


def test_right_angle_input_characterization_reports_fraction(encoding_primitives):
    right_angle = encoding_primitives["right_angle_input_characterization"]
    assert right_angle["total_building_polygon_corner_count"] > 0
    assert "fraction_within_5_deg_of_90" in right_angle
    assert 0.0 <= right_angle["fraction_within_5_deg_of_90"] <= 1.0
    assert right_angle["definition"] == "abs(angle_deg - 90) <= 5"


def test_collinearity_derivation_reports_distribution_and_method(
    encoding_primitives,
):
    collinearity = encoding_primitives["collinearity_candidate_distribution"]
    assert collinearity["total_polyline_interior_triples"] > 0
    assert "collinear_candidate_triples" in collinearity
    assert "weak_empirical_p95_basis" in collinearity
    assert collinearity["weak_empirical_p95_basis"] == (
        collinearity["collinear_candidate_triples"] < 500
    )
    assert collinearity["distribution_perpendicular_m"]["count"] == (
        collinearity["collinear_candidate_triples"]
    )
    assert "proposed_threshold_method" in collinearity
    assert "proposed_threshold_m" in collinearity
    assert "fixed_multiple_thresholds_m" in collinearity
    assert {"1x_magnitude_quantum", "2x_magnitude_quantum"} <= set(
        collinearity["fixed_multiple_thresholds_m"]
    )


def test_anchor_comparison_includes_flat_and_hierarchical(encoding_primitives):
    comparison = encoding_primitives["anchor_scheme_comparison"]
    assert {row["scheme"] for row in comparison} == {"flat", "hierarchical"}
    for row in comparison:
        assert row["anchor_vocab_size"] > 0
        assert row["tokens_per_anchor"] > 0
        assert row["mean_sequence_length_per_cell"] > 0
        assert row["p95_sequence_length_per_cell"] > 0


def test_anchor_vocab_derivation_is_spec_locked(encoding_primitives):
    quantum = encoding_primitives["proposed_lock"]["magnitude_quantum_m"]
    comparison = {
        row["scheme"]: row
        for row in encoding_primitives["anchor_scheme_comparison"]
    }
    assert comparison["flat"]["anchor_vocab_size"] == 2 * math.ceil(250 / quantum)
    assert comparison["flat"]["vocab_derivation"] == (
        "2 * ceil(250 / magnitude_quantum_m)"
    )
    assert comparison["hierarchical"]["anchor_vocab_size"] == 96
    assert comparison["hierarchical"]["vocab_derivation"] == (
        "(16 coarse + 32 fine) * 2 axes"
    )


def test_proposed_lock_uses_approved_halt2_values(
    encoding_primitives,
):
    proposed = encoding_primitives["proposed_lock"]
    assert proposed["direction_count"] == 48
    assert proposed["magnitude_quantum_m"] == 0.5
    assert proposed["anchor_scheme"] == "hierarchical"
    assert proposed["chunk_threshold_m"] == 32
    assert proposed["round_trip_l_inf_threshold_m"] == 4.8
    assert proposed["round_trip_l_inf_threshold_status"] == (
        "LOCKED_HALT_2_APPROVED"
    )
    assert proposed["round_trip_angle_threshold_deg"] == 7.5
    assert proposed["round_trip_angle_threshold_status"] == (
        "LOCKED_HALT_2_APPROVED"
    )
    assert proposed["collinearity_admission_perpendicular_m"] == 0.928048


