def test_linf_decomposition_reports_top_50_and_driver_summary(
    encoding_primitives,
):
    decomposition = encoding_primitives["l_inf_decomposition_proposed_24_0_5"]
    assert decomposition["candidate"] == {
        "direction_count": 24,
        "magnitude_quantum_m": 0.5,
        "geometry_class": "polylines",
    }
    assert decomposition["sample_count"] == 1000
    assert len(decomposition["top_50_worst_polyline_features"]) == 50
    assert "root_cause_classification" in decomposition
    assert "dominant_driver" in decomposition["root_cause_classification"]
    for field in (
        "total_length_m",
        "vertex_count",
        "max_abs_turn_angle_deg",
        "mean_vertex_spacing_m",
    ):
        assert field in decomposition["correlations"]
        assert "pearson" in decomposition["correlations"][field]
        assert "spearman" in decomposition["correlations"][field]
    worst = decomposition["top_50_worst_polyline_features"][0]
    assert {
        "tile_id",
        "source_feature_id",
        "l_inf_m",
        "total_length_m",
        "vertex_count",
        "max_abs_turn_angle_deg",
        "mean_vertex_spacing_m",
    } <= set(worst)


def test_right_angle_decomposition_reports_catastrophic_buckets(
    encoding_primitives,
):
    decomposition = encoding_primitives[
        "right_angle_catastrophic_decomposition_proposed_24_0_5"
    ]
    assert decomposition["candidate"] == {
        "direction_count": 24,
        "magnitude_quantum_m": 0.5,
    }
    bucket_labels = {bucket["bucket"] for bucket in decomposition["buckets"]}
    assert bucket_labels == {
        "<5 deg",
        "5-15 deg",
        "15-45 deg",
        ">45 deg",
    }
    measured = decomposition["measured_right_angle_corner_count"]
    assert measured > 0
    assert sum(bucket["count"] for bucket in decomposition["buckets"]) == measured
    assert "classification" in decomposition
    assert "catastrophic_fraction" in decomposition


def test_linf_chunk_threshold_sweep_reports_all_thresholds(
    encoding_primitives,
):
    sweep = encoding_primitives["l_inf_chunk_threshold_sweep_24_0_5_hierarchical"]
    assert sweep["candidate"] == {
        "direction_count": 24,
        "magnitude_quantum_m": 0.5,
        "anchor_scheme": "hierarchical",
        "geometry_class": "polylines",
    }
    assert [row["chunk_threshold_m"] for row in sweep["rows"]] == [32, 24, 16, 12]
    assert sweep["classification"] == "chunking_is_no_op_on_test_sample"
    assert "proposed_chunk_threshold_m" in sweep
    assert "proposed_l_inf_threshold_m" in sweep
    for row in sweep["rows"]:
        assert row["sample_count"] == 1000
        assert row["skip_count"] == 0
        for field in (
            "roundtrip_l_inf_mean_m",
            "roundtrip_l_inf_p50_m",
            "roundtrip_l_inf_p95_m",
            "roundtrip_l_inf_p99_m",
            "roundtrip_l_inf_max_m",
        ):
            assert field in row
        assert len(row["top_10_worst_polyline_features"]) == 10


def test_proposed_lock_carries_chunk_threshold_metadata(encoding_primitives):
    proposed = encoding_primitives["proposed_lock"]
    sweep = encoding_primitives["l_inf_chunk_threshold_sweep_24_0_5_hierarchical"]
    assert proposed["chunk_threshold_m"] == sweep["proposed_chunk_threshold_m"]
