def test_right_angle_root_cause_reports_hypothesis_buckets(encoding_primitives):
    root = encoding_primitives["right_angle_catastrophic_root_cause_24_0_5"]
    assert root["candidate"] == {
        "direction_count": 24,
        "magnitude_quantum_m": 0.5,
    }
    assert root["catastrophic_corner_count"] > 0
    assert {row["bucket"] for row in root["ring_position_buckets"]} == {
        "position_0_or_1",
        "position_2_to_mid",
        "position_mid_to_last",
    }
    assert {row["bucket"] for row in root["input_deviation_buckets"]} == {
        "<1deg",
        "1_to_3deg",
        "3_to_5deg",
    }
    assert {row["bucket"] for row in root["perimeter_buckets"]} == {
        "<10m",
        "10_to_30m",
        "30_to_100m",
        ">100m",
    }
    for bucket_family in (
        "ring_position_buckets",
        "input_deviation_buckets",
        "perimeter_buckets",
    ):
        assert sum(row["count"] for row in root[bucket_family]) == (
            root["catastrophic_corner_count"]
        )
    assert "root_cause_classification" in root
    assert "classification" in root["root_cause_classification"]


def test_direction_count_sweep_reports_bp2_fit_and_proposal(encoding_primitives):
    sweep = encoding_primitives["l_inf_direction_count_sweep_0_5_hierarchical"]
    assert sweep["candidate"] == {
        "magnitude_quantum_m": 0.5,
        "anchor_scheme": "hierarchical",
        "chunk_threshold_m": 32,
        "geometry_class": "polylines",
    }
    assert [row["direction_count"] for row in sweep["rows"]] == [24, 32, 48, 72]
    assert sweep["proposed_direction_count"] in {24, 48}
    assert "classification" in sweep
    for row in sweep["rows"]:
        assert row["sample_count"] == 1000
        assert row["skip_count"] == 0
        assert row["bp2_fit"]["components"] == {
            "anchor_vocab_size": 96,
            "direction_vocab_size": row["direction_count"],
            "magnitude_vocab_size": 65,
            "structural_sentinel_count": 0,
        }
        assert row["bp2_fit"]["fits_placeholder"] is True
        for field in (
            "roundtrip_l_inf_mean_m",
            "roundtrip_l_inf_p50_m",
            "roundtrip_l_inf_p95_m",
            "roundtrip_l_inf_p99_m",
            "roundtrip_l_inf_max_m",
        ):
            assert field in row


def test_anchor_verification_documents_measurement_inconsistency(
    encoding_primitives,
):
    verification = encoding_primitives["anchor_verification_cross_measurement"]
    assert verification["joint_surface_anchor_scheme"] == "anchor_scheme_independent"
    assert verification["joint_surface_geometry_scope"] == (
        "combined_polylines_and_polygon_exterior_rings"
    )
    assert verification["lock_threshold_surface_anchor_scheme"] == "hierarchical"
    assert verification["verified_inconsistency_cause"] == (
        "geometry_scope_difference_not_anchor_scheme"
    )


def test_right_angle_known_loss_and_threshold_proposal(encoding_primitives):
    proposal = encoding_primitives["right_angle_v1_known_loss_threshold_proposal"]
    root = encoding_primitives["right_angle_catastrophic_root_cause_24_0_5"]
    assert root["right_angle_catastrophic_v1_classification"] == (
        "accepted_v1_known_loss_cascade_8_candidate_for_sub_f_v2"
    )
    assert proposal["threshold_basis"] == "non_catastrophic_post_deviation_p95"
    assert proposal["excluded_catastrophic_gt_45_deg"] is True
    assert proposal["round_trip_angle_threshold_status"] == (
        "PROPOSED_V1_KNOWN_LOSS_EXCLUDING_CATASTROPHIC"
    )
    assert proposal["round_trip_angle_threshold_deg"] > 0


def test_protocol_v2_candidate_9_capture_is_documented(encoding_primitives):
    note = encoding_primitives["protocol_v2_candidate_9_capture"]
    assert note["candidate"] == 9
    assert note["classification"] == "hypothesis_falsified_capture"
